// This program implements a sorting algorithm that can be evolved to adapt to different data patterns

use std::cmp::Ordering;

// EVOLVE-BLOCK-START
// Optimized hybrid sort: O(n) scan, median-of-three, 3-way partition, and shifting insertion sort.
pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n < 2 { return; }
    let (mut s, mut r) = (true, true);
    for i in 0..n-1 {
        if arr[i] > arr[i+1] { s = false; }
        if arr[i] < arr[i+1] { r = false; }
        if !s && !r { break; }
    }
    if s { return; }
    if r { arr.reverse(); return; }
    qsort(arr);
}

fn qsort<T: Ord + Clone>(a: &mut [T]) {
    let n = a.len();
    if n < 24 {
        for i in 1..n {
            let v = a[i].clone();
            let mut j = i;
            while j > 0 && a[j-1] > v { a[j] = a[j-1].clone(); j -= 1; }
            a[j] = v;
        }
        return;
    }
    let m = n / 2;
    if a[m] < a[0] { a.swap(0, m); }
    if a[n-1] < a[0] { a.swap(0, n-1); }
    if a[n-1] < a[m] { a.swap(m, n-1); }
    let p = a[m].clone();
    let (mut l, mut i, mut g) = (0, 0, n);
    while i < g {
        match a[i].cmp(&p) {
            Ordering::Less => { a.swap(l, i); l += 1; i += 1; }
            Ordering::Greater => { g -= 1; a.swap(i, g); }
            _ => i += 1,
        }
    }
    qsort(&mut a[..l]); qsort(&mut a[g..]);
}
